import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;

public class FileHandler {
    private static final String BASE_PATH = "/path/to/files/";

    public static void readFile(String fileName) {
        try {
            File file = new File(BASE_PATH + fileName);

            if (file.getCanonicalPath().startsWith(new File(BASE_PATH).getCanonicalPath())) {
                FileInputStream fis = new FileInputStream(file);
                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }
                fis.close();
            } else {
                System.out.println("Access to file outside allowed directory is forbidden.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    public static void main(String[] args) {
        String userInput = "file.txt";
        readFile(userInput);
    }
}

